"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[8357],{3014(i){i.exports=JSON.parse('{"tag":{"label":"decentralization","permalink":"/tags/decentralization","allTagsPath":"/tags","count":4,"items":[{"id":"concepts/ai-and-bitcoin","title":"AI and Bitcoin","description":"The intersection of artificial intelligence and Bitcoin presents both risks and opportunities. AI benefits from decentralization, privacy, and permissionless payment rails \u2014 while Bitcoin benefits from AI-assisted tooling for content, code, and automation.","permalink":"/concepts/ai-and-bitcoin"},{"id":"concepts/home-mining","title":"Home Mining","description":"The practice of mining Bitcoin from a residence or small office using low-to-medium power hardware. Contrasts with industrial-scale mining in dedicated facilities. Home mining has seen a resurgence with the rise of efficient, quiet, open-source ASICs and hashrate marketplaces that let participants rent industrial-scale hash without owning hardware.","permalink":"/concepts/home-mining"},{"id":"summaries/mining-decentralization","title":"Mining Decentralization","description":"Proof-of-Work is what makes Bitcoin immutable. At Meetup #2 and again in January 2026 we covered the mechanics: miners hash block data, race for a valid nonce, and broadcast solutions that the network accepts. The difficulty adjustment targets ten minutes per block. The supply cap is twenty-one million. None of this works without distributed hash rate competing to find the next block.","permalink":"/summaries/mining-decentralization"},{"id":"entities/stratum-v2","title":"Stratum V2","description":"Stratum V2 (Sv2) is a next-generation mining protocol that addresses the centralization risks inherent in the original Stratum protocol by giving miners control over block template construction.","permalink":"/entities/stratum-v2"}],"unlisted":false}}')}}]);